// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "./SablierToken.sol";

contract SablierTokenTest is Test {
    SablierToken token;

    function setUp() public {
        token = new SablierToken(1000 ether);
    }

    function testBurn() public {
        token.transfer(address(1), 500 ether);
        vm.prank(address(1));
        token.burn(250 ether);
        assertEq(token.balanceOf(address(1)), 250 ether);
    }

    function testBurnRevertsIfInsufficientBalance() public {
        vm.expectRevert("Insufficient balance");
        vm.prank(address(1));
        token.burn(1001 ether);
    }

    function testMint() public {
        token.mint(address(2), 300 ether);
        assertEq(token.balanceOf(address(2)), 300 ether);
    }

    function testTransferOwnership() public {
        token.transferOwnership(address(3));
        assertEq(token.owner(), address(3));
    }

    function testTransferOwnershipRevertsIfZeroAddress() public {
        vm.expectRevert("New owner cannot be the zero address");
        token.transferOwnership(address(0));
    }
}
